  if (!inherits(plot, "ggplot")) stop("plot must be a ggplot object.")
  text_element <- if (isTRUE(keep_labels)) ggplot2::element_text() else ggplot2::element_blank()
  plot + ggplot2::theme(
    panel.border = ggplot2::element_blank(), panel.grid = ggplot2::element_blank(),
    axis.line = ggplot2::element_blank(), axis.ticks = ggplot2::element_blank(),
    axis.text = text_element, axis.title = text_element
  )
}

plot_box_jitter <- function(data, group = "group", value = "value", sample = NULL,
                            palette = NULL, point_size = 2, jitter_width = 0.12,
                            show_mean = TRUE) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) stop("Package 'ggplot2' is required.")
  needed <- c(group, value, if (!is.null(sample)) sample)
  if (!is.data.frame(data) || !all(needed %in% names(data))) stop("Missing columns: ", paste(setdiff(needed, names(data)), collapse = ", "))
  p <- ggplot2::ggplot(data, ggplot2::aes(x = .data[[group]], y = .data[[value]], fill = .data[[group]])) +
    ggplot2::geom_boxplot(width = 0.55, outlier.shape = NA, alpha = 0.55, colour = "black") +
    ggplot2::geom_jitter(ggplot2::aes(colour = .data[[group]]), width = jitter_width, height = 0, size = point_size, alpha = 0.85, show.legend = FALSE) +
    ggplot2::labs(x = NULL, y = value, fill = group) + ggplot2::theme_classic(base_size = 11) +
    ggplot2::theme(legend.position = "none")
  if (isTRUE(show_mean)) p <- p + ggplot2::stat_summary(fun = mean, geom = "point", shape = 23, size = 3, fill = "white", colour = "black")
  if (!is.null(palette)) p <- p + ggplot2::scale_fill_manual(values = palette) + ggplot2::scale_colour_manual(values = palette)
  p
}

plot_cellchat_chord <- function(adjacency, group_colours = NULL, transparency = 0.65,
                                link_border = NA, directional = TRUE) {
  if (!requireNamespace("circlize", quietly = TRUE)) stop("Package 'circlize' is required.")
  x <- as.matrix(adjacency)
  storage.mode(x) <- "double"
  if (nrow(x) != ncol(x)) stop("adjacency must be square.")
  if (is.null(rownames(x)) || is.null(colnames(x))) stop("adjacency needs row and column names.")
  if (!setequal(rownames(x), colnames(x))) stop("row and column node sets must match.")
  x <- x[rownames(x), rownames(x), drop = FALSE]
  if (any(x < 0, na.rm = TRUE)) stop("Interaction weights must be non-negative.")
  if (!is.null(group_colours) && !all(rownames(x) %in% names(group_colours))) stop("group_colours must be named for every node.")
  on.exit(circlize::circos.clear(), add = TRUE)
  circlize::circos.clear()
  circlize::chordDiagram(
    x, grid.col = group_colours, transparency = transparency,
    directional = if (directional) 1 else 0,
    direction.type = if (directional) c("arrows", "diffHeight") else "diffHeight",
    link.arr.type = if (directional) "big.arrow" else "triangle",
    link.border = link_border, annotationTrack = c("grid", "name")
  )
  invisible(list(adjacency = x, directional = directional))
}

plot_cellchat_circle <- function(adjacency, group_colours = NULL,
                                 vertex_weight = NULL, edge_width_max = 8,
                                 edge_alpha = 0.45, label_size = 0.9,
                                 title = "Inferred communication weight") {
  if (!requireNamespace("igraph", quietly = TRUE)) stop("Package 'igraph' is required.")
  x <- as.matrix(adjacency)
  storage.mode(x) <- "double"
  if (nrow(x) != ncol(x)) stop("adjacency must be square.")
  if (is.null(rownames(x)) || is.null(colnames(x))) stop("adjacency needs row and column names.")
  if (!setequal(rownames(x), colnames(x))) stop("row and column node sets must match.")
  x <- x[rownames(x), rownames(x), drop = FALSE]
  if (any(!is.finite(x)) || any(x < 0)) stop("adjacency must contain finite non-negative weights.")
  nodes <- rownames(x)
  if (is.null(group_colours)) {
    hues <- seq(15, 375, length.out = length(nodes) + 1L)[seq_along(nodes)]
    group_colours <- stats::setNames(grDevices::hcl(h = hues, c = 75, l = 60), nodes)
  }
  if (is.null(names(group_colours)) || !all(nodes %in% names(group_colours))) stop("group_colours must be named for every node.")
  if (is.null(vertex_weight)) vertex_weight <- rowSums(x) + colSums(x)
  if (length(vertex_weight) != length(nodes)) stop("vertex_weight must have one value per node.")
  vertex_weight <- as.numeric(vertex_weight)
  vertex_size <- if (diff(range(vertex_weight)) == 0) rep(24, length(nodes)) else 18 + 18 * (vertex_weight - min(vertex_weight)) / diff(range(vertex_weight))
  graph <- igraph::graph_from_adjacency_matrix(x, mode = "directed", weighted = TRUE, diag = TRUE)
  weights <- igraph::E(graph)$weight
  widths <- if (!length(weights)) numeric() else if (max(weights) == 0) rep(0.5, length(weights)) else pmax(0.35, weights / max(weights) * edge_width_max)
  igraph::plot.igraph(
    graph, layout = igraph::layout_in_circle(graph), rescale = TRUE,
    vertex.color = unname(group_colours[igraph::V(graph)$name]),
    vertex.frame.color = "white", vertex.size = vertex_size,
    vertex.label.color = "#17202A", vertex.label.cex = label_size,
    vertex.label.family = "sans", edge.width = widths,
    edge.color = grDevices::adjustcolor("#34495E", alpha.f = edge_alpha),
    edge.arrow.size = 0.38, edge.curved = 0.16, margin = 0.16,
    main = title
  )
  invisible(list(adjacency = x, vertex_weight = vertex_weight, edge_width_max = edge_width_max))
}

# Extract CellChat ligand-receptor communication rows into a stable plotting
# contract. A list with a `communication` data.frame supports deterministic tests.
cellchat_lr_table <- function(object, slot_name = "net", threshold = 0.05,
                              sources_use = NULL, targets_use = NULL) {
  if (inherits(object, "CellChat") && !requireNamespace("CellChat", quietly = TRUE)) stop("Package 'CellChat' is required.")
  if (is.list(object) && !is.null(object$communication)) {
    raw <- object$communication
  } else if (methods::is(object, "CellChat")) {
    raw <- CellChat::subsetCommunication(
      object, slot.name = slot_name, thresh = threshold,
      sources.use = sources_use, targets.use = targets_use
    )
  } else {
    stop("object must be a CellChat object or a list with a 'communication' data.frame.")
  }
  if (!is.data.frame(raw) || !nrow(raw)) stop("No communication rows were available at the declared threshold.")
  choose <- function(candidates, label, required = TRUE) {
    hit <- candidates[candidates %in% names(raw)][1]
    if (is.na(hit) && required) stop("Communication table is missing ", label, ": expected one of ", paste(candidates, collapse = ", "))
    hit
  }
  source_col <- choose(c("source", "sources"), "source")
  target_col <- choose(c("target", "targets"), "target")
  interaction_col <- choose(c("interaction_name_2", "interaction_name", "interaction", "ligand_receptor"), "interaction")
  probability_col <- choose(c("prob", "probability", "weight"), "probability")
  p_col <- choose(c("pval", "p_value", "p.value", "pvalue"), "p-value", required = FALSE)
  pathway_col <- choose(c("pathway_name", "pathway"), "pathway", required = FALSE)
  out <- data.frame(
    source = as.character(raw[[source_col]]),
    target = as.character(raw[[target_col]]),
    interaction = as.character(raw[[interaction_col]]),
    probability = as.numeric(raw[[probability_col]]),
    p_value = if (is.na(p_col)) NA_real_ else as.numeric(raw[[p_col]]),
    pathway = if (is.na(pathway_col)) NA_character_ else as.character(raw[[pathway_col]]),
    stringsAsFactors = FALSE
  )
  if (any(!is.finite(out$probability)) || any(out$probability < 0)) stop("Communication probabilities/weights must be finite and non-negative.")
  if (any(!is.na(out$p_value) & (!is.finite(out$p_value) | out$p_value < 0 | out$p_value > 1))) stop("p-values must be missing or lie in [0, 1].")
  out$source_target <- paste(out$source, out$target, sep = " → ")
  rownames(out) <- NULL
  attr(out, "cellchat_extraction") <- list(slot_name = slot_name, threshold = threshold)
  out
}

# Extract CellChat's aggregate network matrix into the contract used by the
# chord recipe. A list-shaped mock is supported for deterministic testing.
cellchat_interaction_data <- function(object, measure = "weight",
                                      output = c("matrix", "long"), drop_zero = FALSE) {
  output <- match.arg(output)
  if (inherits(object, "CellChat") && !requireNamespace("CellChat", quietly = TRUE)) stop("Package 'CellChat' is required.")
  net <- NULL
  if (is.list(object) && !is.null(object$net)) {
    net <- object$net
  } else if (methods::is(object, "CellChat")) {
    net <- methods::slot(object, "net")
  }
  if (is.null(net) || !is.list(net)) stop("object must be a CellChat object or a list with a 'net' list.")
  if (!measure %in% names(net)) stop("Network measure not found: ", measure)
  matrix_data <- as.matrix(net[[measure]])
  storage.mode(matrix_data) <- "double"
  if (nrow(matrix_data) != ncol(matrix_data)) stop("The selected CellChat aggregate network must be square.")
  if (is.null(rownames(matrix_data)) || is.null(colnames(matrix_data))) stop("The network needs source and target names.")
  if (!setequal(rownames(matrix_data), colnames(matrix_data))) stop("Source and target node sets must match.")
  matrix_data <- matrix_data[rownames(matrix_data), rownames(matrix_data), drop = FALSE]
  if (any(!is.finite(matrix_data)) || any(matrix_data < 0)) stop("Network weights must be finite and non-negative.")
  if (output == "matrix") return(matrix_data)
  long <- as.data.frame(as.table(matrix_data), stringsAsFactors = FALSE)
  names(long) <- c("source", "target", "weight")
  if (isTRUE(drop_zero)) long <- long[long$weight != 0, , drop = FALSE]
  rownames(long) <- NULL
  long
}

plot_annotated_heatmap <- function(matrix_data, row_group = NULL, column_group = NULL,
                                   significance = NULL,
                                   colours = c("#006D5B", "#F7F7F7", "#E66101"),
                                   limits = NULL, name = "value",
                                   row_title_fontsize = 8) {
  if (!requireNamespace("ComplexHeatmap", quietly = TRUE)) stop("Package 'ComplexHeatmap' is required.")
  if (!requireNamespace("circlize", quietly = TRUE)) stop("Package 'circlize' is required.")
  x <- as.matrix(matrix_data)
  storage.mode(x) <- "double"
  if (!length(x) || any(!is.finite(x), na.rm = TRUE)) stop("matrix_data must contain finite numeric values or NA.")
  if (is.null(limits)) {
    lim <- max(abs(x), na.rm = TRUE)
    if (!is.finite(lim) || lim == 0) lim <- 1
    limits <- c(-lim, 0, lim)
  }
  if (length(limits) != 3 || limits[1] >= limits[2] || limits[2] >= limits[3]) stop("limits must be three increasing values.")
  if (length(row_title_fontsize) != 1 || !is.finite(row_title_fontsize) || row_title_fontsize <= 0) stop("row_title_fontsize must be a positive number.")
  col_fun <- circlize::colorRamp2(limits, colours)
  top_anno <- NULL
  if (!is.null(column_group)) {
    if (length(column_group) != ncol(x)) stop("column_group length must equal ncol(matrix_data).")
    top_anno <- ComplexHeatmap::HeatmapAnnotation(group = column_group)
  }
  split <- NULL
  if (!is.null(row_group)) {
    if (length(row_group) != nrow(x)) stop("row_group length must equal nrow(matrix_data).")
    split <- row_group
  }
  cell_fun <- NULL
  if (!is.null(significance)) {
    significance <- as.matrix(significance)
    if (!identical(dim(significance), dim(x))) stop("significance must have the same dimensions as matrix_data.")
    cell_fun <- function(j, i, x0, y0, width, height, fill) {
      if (!is.na(significance[i, j]) && nzchar(as.character(significance[i, j]))) {
        grid::grid.text(as.character(significance[i, j]), x0, y0, gp = grid::gpar(fontsize = 8))
      }
    }
  }
  ComplexHeatmap::Heatmap(
    x, name = name, col = col_fun, cluster_rows = FALSE, cluster_columns = FALSE,
    row_split = split, top_annotation = top_anno, cell_fun = cell_fun,
    row_names_gp = grid::gpar(fontsize = 9), column_names_gp = grid::gpar(fontsize = 9),
    row_title_gp = grid::gpar(fontsize = row_title_fontsize)
  )
}

