plot_roc_curve <- function(data, outcome = "outcome", score = "score", positive = NULL,
                           direction = "auto", line_colour = "#2166AC") {
  if (!requireNamespace("pROC", quietly = TRUE)) stop("Package 'pROC' is required.")
  if (!requireNamespace("ggplot2", quietly = TRUE)) stop("Package 'ggplot2' is required.")
  if (!is.data.frame(data) || !all(c(outcome, score) %in% names(data))) stop("data must contain outcome and score columns.")
  y <- factor(data[[outcome]])
  if (nlevels(y) != 2) stop("outcome must have exactly two observed levels.")
  if (!is.null(positive)) {
    if (!positive %in% levels(y)) stop("positive must be an observed outcome level.")
    y <- stats::relevel(y, ref = setdiff(levels(y), positive)[1])
  }
  roc_obj <- pROC::roc(response = y, predictor = as.numeric(data[[score]]), direction = direction, quiet = TRUE)
  curve <- data.frame(fpr = 1 - roc_obj$specificities, sensitivity = roc_obj$sensitivities)
  auc_value <- as.numeric(pROC::auc(roc_obj))
  p <- ggplot2::ggplot(curve, ggplot2::aes(x = .data[["fpr"]], y = .data[["sensitivity"]])) +
    ggplot2::geom_abline(slope = 1, intercept = 0, colour = "grey70", linewidth = 0.4) +
    ggplot2::geom_path(colour = line_colour, linewidth = 0.9) +
    ggplot2::coord_equal(xlim = c(0, 1), ylim = c(0, 1), expand = FALSE) +
    ggplot2::annotate("text", x = 0.65, y = 0.12, label = sprintf("AUC = %.3f", auc_value), hjust = 0) +
    ggplot2::labs(x = "1 - Specificity", y = "Sensitivity") + ggplot2::theme_classic(base_size = 11)
  structure(list(plot = p, roc = roc_obj, auc = auc_value), class = "plot_recipe_roc")
}

# Convert a caller-supplied Seurat reduction and metadata column into the
# backend-neutral data-frame contract consumed by umap-dataframe-r-v1.
seurat_embedding_frame <- function(object, reduction = "umap", group = "seurat_clusters",
                                   dimensions = c(1L, 2L), x_name = "umap_1",
                                   y_name = "umap_2", group_name = "cluster") {
  if (!inherits(object, "Seurat")) stop("object must inherit from 'Seurat'.")
  if (!requireNamespace("SeuratObject", quietly = TRUE)) stop("Package 'SeuratObject' is required to read a Seurat object.")
  if (length(dimensions) != 2L || any(!is.finite(dimensions)) || any(dimensions < 1) || any(dimensions != as.integer(dimensions))) {
    stop("dimensions must contain two positive integer indices.")
  }
  reduction_object <- tryCatch(object[[reduction]], error = function(e) NULL)
  if (is.null(reduction_object)) stop("Reduction not found: ", reduction)
  coordinates <- SeuratObject::Embeddings(reduction_object)
  if (max(dimensions) > ncol(coordinates)) stop("Requested dimensions exceed the reduction width.")
  metadata <- object[[]]
  if (!group %in% names(metadata)) stop("Metadata column not found: ", group)
  if (is.null(rownames(coordinates)) || is.null(rownames(metadata))) stop("Coordinates and metadata must have cell row names.")
  missing_cells <- setdiff(rownames(coordinates), rownames(metadata))
  if (length(missing_cells)) stop("Metadata is missing cells present in the reduction.")
  metadata <- metadata[rownames(coordinates), , drop = FALSE]
  out <- data.frame(
    observation_id = rownames(coordinates),
    x = as.numeric(coordinates[, dimensions[1]]),
    y = as.numeric(coordinates[, dimensions[2]]),
    group = metadata[[group]],
    stringsAsFactors = FALSE,
    check.names = FALSE
  )
  names(out)[2:4] <- c(x_name, y_name, group_name)
  out
}

# Summarize a caller-supplied Seurat expression layer into the explicit long
# table consumed by marker-dotplot-r-v1. The Seurat object is never modified.
seurat_marker_summary <- function(object, features, group = "seurat_clusters",
                                  assay = NULL, layer = "data",
                                  average_transform = c("expm1", "identity"),
                                  scale_average = FALSE, scale_clip = 2.5) {
  if (!inherits(object, "Seurat")) stop("object must inherit from 'Seurat'.")
  if (!requireNamespace("SeuratObject", quietly = TRUE)) stop("Package 'SeuratObject' is required.")
  if (!requireNamespace("Matrix", quietly = TRUE)) stop("Package 'Matrix' is required.")
  average_transform <- match.arg(average_transform)
  features <- unique(as.character(features))
  if (!length(features) || anyNA(features) || any(!nzchar(features))) stop("features must contain unique non-empty feature names.")
  metadata <- object[[]]
  if (!group %in% names(metadata)) stop("Metadata column not found: ", group)
  if (is.null(assay)) assay <- SeuratObject::DefaultAssay(object)
  expression <- SeuratObject::LayerData(object, assay = assay, layer = layer)
  available <- intersect(features, rownames(expression))
  missing <- setdiff(features, rownames(expression))
  if (length(missing)) warning("Features absent from the selected assay/layer were omitted: ", paste(missing, collapse = ", "))
  if (!length(available)) stop("None of the requested features are present in the selected assay/layer.")
  if (is.null(colnames(expression)) || is.null(rownames(metadata))) stop("Expression and metadata need cell names.")
  absent_cells <- setdiff(colnames(expression), rownames(metadata))
  if (length(absent_cells)) stop("Metadata is missing cells present in the expression layer.")
  metadata <- metadata[colnames(expression), , drop = FALSE]
  groups <- metadata[[group]]
  if (anyNA(groups)) stop("Grouping metadata contains missing values.")
  group_levels <- if (is.factor(groups)) levels(droplevels(groups)) else unique(as.character(groups))
  groups <- factor(as.character(groups), levels = group_levels)
  expression <- expression[available, , drop = FALSE]

  rows <- lapply(group_levels, function(level) {
    selected <- which(groups == level)
    values <- expression[, selected, drop = FALSE]
    average_values <- if (average_transform == "expm1") Matrix::rowMeans(expm1(values)) else Matrix::rowMeans(values)
    data.frame(
      cell_type = level,
      gene = available,
      avg_expression_unscaled = as.numeric(average_values),
      pct_expression = as.numeric(Matrix::rowMeans(values > 0) * 100),
      stringsAsFactors = FALSE
    )
  })
  result <- do.call(rbind, rows)
  result$avg_expression <- result$avg_expression_unscaled
  if (isTRUE(scale_average)) {
    result$avg_expression <- ave(result$avg_expression_unscaled, result$gene, FUN = function(value) {
      if (length(value) < 2L || !is.finite(stats::sd(value)) || stats::sd(value) == 0) return(rep(0, length(value)))
      pmax(-scale_clip, pmin(scale_clip, as.numeric(scale(value))))
    })
  }
  result$cell_type <- factor(result$cell_type, levels = group_levels)
  result$gene <- factor(result$gene, levels = rev(available))
  attr(result, "aggregation") <- list(
    assay = assay, layer = layer, average_transform = average_transform,
    scale_average = isTRUE(scale_average), scale_clip = scale_clip,
    denominator = "cells within displayed group"
  )
  rownames(result) <- NULL
  result
}

# Coordinate-faithful Visium spot overlays for caller-supplied Seurat objects.
#
# The recipe validates the Spatial assay, image association, scale factors, and
# barcode/coordinate reconciliation before delegating drawing to Seurat's
# SpatialDimPlot or SpatialFeaturePlot. It does not reconstruct coordinates or
# alter the caller's object.

.seurat_spatial_contract <- function(object, assay, image, image_scale) {
  if (!inherits(object, "Seurat")) {
    stop("object must inherit from 'Seurat'.", call. = FALSE)
  }
  if (!requireNamespace("Seurat", quietly = TRUE)) {
    stop("Package 'Seurat' is required.", call. = FALSE)
  }
  if (!requireNamespace("SeuratObject", quietly = TRUE)) {
    stop("Package 'SeuratObject' is required.", call. = FALSE)
  }
  if (!is.character(assay) || length(assay) != 1L || !nzchar(assay)) {
    stop("assay must be one non-empty name.", call. = FALSE)
  }
  if (!assay %in% SeuratObject::Assays(object)) {
    stop("Assay not found: ", assay, call. = FALSE)
  }

  assay_images <- Seurat::Images(object, assay = assay)
  if (!length(assay_images)) {
    stop("No spatial image is associated with assay '", assay, "'.", call. = FALSE)
  }
  if (is.null(image)) {
    if (length(assay_images) != 1L) {
      stop(
        "Multiple images are associated with assay '", assay,
        "'; select one explicitly with image=.",
        call. = FALSE
      )
    }
    image <- assay_images[[1L]]
  }
  if (!is.character(image) || length(image) != 1L || !nzchar(image)) {
    stop("image must be one non-empty image name.", call. = FALSE)
  }
  if (!image %in% assay_images) {
    stop("Image '", image, "' is not associated with assay '", assay, "'.", call. = FALSE)
  }

  spatial_image <- object[[image]]
  image_assay <- SeuratObject::DefaultAssay(spatial_image)
  if (!identical(image_assay, assay)) {
    stop(
      "Image '", image, "' declares assay '", image_assay,
      "', not '", assay, "'.",
      call. = FALSE
    )
  }

  scale_factors <- tryCatch(
    Seurat::ScaleFactors(spatial_image),
    error = function(error) {
      stop("Could not read image scale factors: ", conditionMessage(error), call. = FALSE)
    }
  )
  required_scales <- unique(c("spot", image_scale))
  scale_values <- vapply(
    required_scales,
    function(scale_name) {
      value <- scale_factors[[scale_name]]
      if (is.null(value) || length(value) != 1L || !is.finite(value) || value <= 0) {
        stop("Missing or invalid '", scale_name, "' scale factor.", call. = FALSE)
      }
      as.numeric(value)
    },
    numeric(1)
  )

  assay_barcodes <- SeuratObject::Cells(object[[assay]])
  image_barcodes <- SeuratObject::Cells(spatial_image)
  raw_coordinates <- Seurat::GetTissueCoordinates(spatial_image, scale = NULL)
  scaled_coordinates <- Seurat::GetTissueCoordinates(spatial_image, scale = image_scale)
  coordinate_barcodes <- rownames(raw_coordinates)

  if (!length(assay_barcodes) || !length(image_barcodes)) {
    stop("Assay and image must both contain barcodes.", call. = FALSE)
  }
  if (is.null(coordinate_barcodes) || any(!nzchar(coordinate_barcodes))) {
    stop("Tissue coordinates must use barcodes as row names.", call. = FALSE)
  }
  if (anyDuplicated(image_barcodes) || anyDuplicated(coordinate_barcodes)) {
    stop("Image barcodes and coordinate row names must be unique.", call. = FALSE)
  }
  if (!setequal(image_barcodes, coordinate_barcodes)) {
    missing_coordinates <- setdiff(image_barcodes, coordinate_barcodes)
    orphan_coordinates <- setdiff(coordinate_barcodes, image_barcodes)
    stop(
      "Image barcode-coordinate reconciliation failed (missing coordinates: ",
      length(missing_coordinates), "; orphan coordinates: ",
      length(orphan_coordinates), ").",
      call. = FALSE
    )
  }
  missing_assay_barcodes <- setdiff(image_barcodes, assay_barcodes)
  missing_image_barcodes <- setdiff(assay_barcodes, image_barcodes)
  if (length(missing_assay_barcodes) || length(missing_image_barcodes)) {
    stop(
      "Assay/image barcode-coordinate reconciliation failed (image barcodes absent from assay: ",
      length(missing_assay_barcodes), "; assay barcodes absent from image coordinates: ",
      length(missing_image_barcodes), ").",
      call. = FALSE
    )
  }
  if (ncol(raw_coordinates) < 2L || ncol(scaled_coordinates) < 2L) {
    stop("Tissue coordinates must contain two spatial dimensions.", call. = FALSE)
  }
  raw_numeric <- vapply(raw_coordinates, is.numeric, logical(1))
  scaled_numeric <- vapply(scaled_coordinates, is.numeric, logical(1))
  if (sum(raw_numeric) < 2L || sum(scaled_numeric) < 2L) {
    stop("Tissue coordinate dimensions must be numeric.", call. = FALSE)
  }
  if (
    any(!is.finite(as.matrix(raw_coordinates[, raw_numeric, drop = FALSE]))) ||
      any(!is.finite(as.matrix(scaled_coordinates[, scaled_numeric, drop = FALSE])))
  ) {
    stop("Tissue coordinates must be finite before and after scaling.", call. = FALSE)
  }

  list(
    image = image,
    barcodes = image_barcodes,
    scale_factors = scale_values,
    coordinate_rows = nrow(raw_coordinates)
  )
}


plot_seurat_spatial_overlay <- function(
    object,
    mode = c("identity", "feature"),
    assay = "Spatial",
    feature_assay = NULL,
    image = NULL,
    group_by = NULL,
    features = NULL,
    cols = NULL,
    crop = TRUE,
    label = FALSE,
    label_size = 3.5,
    label_repel = TRUE,
    pt_size_factor = 1.6,
    spot_alpha = 1,
    image_alpha = 1,
    image_scale = c("lowres", "hires")) {
  mode <- match.arg(mode)
  image_scale <- match.arg(image_scale)
  if (!is.logical(crop) || length(crop) != 1L || is.na(crop)) {
    stop("crop must be TRUE or FALSE.", call. = FALSE)
  }
  if (!is.logical(label) || length(label) != 1L || is.na(label)) {
    stop("label must be TRUE or FALSE.", call. = FALSE)
  }
  if (!is.numeric(label_size) || length(label_size) != 1L ||
      !is.finite(label_size) || label_size <= 0) {
    stop("label_size must be one positive finite number.", call. = FALSE)
  }
  if (!is.logical(label_repel) || length(label_repel) != 1L || is.na(label_repel)) {
    stop("label_repel must be TRUE or FALSE.", call. = FALSE)
  }
  if (!is.numeric(pt_size_factor) || length(pt_size_factor) != 1L ||
      !is.finite(pt_size_factor) || pt_size_factor <= 0) {
    stop("pt_size_factor must be one positive finite number.", call. = FALSE)
  }
  if (!is.numeric(spot_alpha) || length(spot_alpha) != 1L ||
      !is.finite(spot_alpha) || spot_alpha < 0 || spot_alpha > 1) {
    stop("spot_alpha must be one finite number in [0, 1].", call. = FALSE)
  }
  if (!is.numeric(image_alpha) || length(image_alpha) != 1L ||
      !is.finite(image_alpha) || image_alpha < 0 || image_alpha > 1) {
    stop("image_alpha must be one finite number in [0, 1].", call. = FALSE)
  }

  contract <- .seurat_spatial_contract(object, assay, image, image_scale)

  # R uses copy-on-modify here: the caller's object remains unchanged while the
  # selected Spatial assay becomes explicit for Seurat's plotting API.
  plot_object <- object
  SeuratObject::DefaultAssay(plot_object) <- assay

  if (mode == "identity") {
    if (!is.null(feature_assay)) {
      stop("feature_assay is only valid when mode='feature'.", call. = FALSE)
    }
    if (!is.null(features)) {
      stop("features is only valid when mode='feature'.", call. = FALSE)
    }
    if (!is.null(group_by)) {
      if (!is.character(group_by) || length(group_by) != 1L || !nzchar(group_by)) {
        stop("group_by must be NULL or one non-empty metadata column.", call. = FALSE)
      }
      metadata <- plot_object[[]]
      if (!group_by %in% colnames(metadata)) {
        stop("Metadata column not found: ", group_by, call. = FALSE)
      }
      if (anyNA(metadata[contract$barcodes, group_by, drop = TRUE])) {
        stop("group_by contains missing values for selected image barcodes.", call. = FALSE)
      }
    } else {
      identities <- SeuratObject::Idents(plot_object)[contract$barcodes]
      if (anyNA(identities)) {
        stop("Active identities contain missing values for selected image barcodes.", call. = FALSE)
      }
    }
    plot <- Seurat::SpatialDimPlot(
      object = plot_object,
      group.by = group_by,
      images = contract$image,
      cols = cols,
      crop = crop,
      label = label,
      label.size = label_size,
      repel = label_repel,
      combine = TRUE,
      pt.size.factor = pt_size_factor,
      alpha = c(spot_alpha, spot_alpha),
      image.alpha = image_alpha,
      image.scale = image_scale
    )
  } else {
    if (!is.null(group_by)) {
      stop("group_by is only valid when mode='identity'.", call. = FALSE)
    }
    if (!is.character(features) || !length(features) || any(!nzchar(features))) {
      stop("features must contain at least one non-empty feature name.", call. = FALSE)
    }
    if (is.null(feature_assay)) {
      feature_assay <- assay
    }
    if (!is.character(feature_assay) || length(feature_assay) != 1L || !nzchar(feature_assay)) {
      stop("feature_assay must be NULL or one non-empty assay name.", call. = FALSE)
    }
    if (!feature_assay %in% SeuratObject::Assays(plot_object)) {
      stop("Feature assay not found: ", feature_assay, call. = FALSE)
    }
    feature_barcodes <- SeuratObject::Cells(plot_object[[feature_assay]])
    missing_feature_barcodes <- setdiff(contract$barcodes, feature_barcodes)
    orphan_feature_barcodes <- setdiff(feature_barcodes, contract$barcodes)
    if (length(missing_feature_barcodes) || length(orphan_feature_barcodes)) {
      stop(
        "Feature-assay/image barcode-coordinate reconciliation failed (image barcodes absent from feature assay: ",
        length(missing_feature_barcodes), "; feature-assay barcodes absent from image coordinates: ",
        length(orphan_feature_barcodes), ").",
        call. = FALSE
      )
    }
    data_layers <- SeuratObject::Layers(plot_object[[feature_assay]], search = "data")
    if (!length(data_layers)) {
      stop(
        "Feature assay '", feature_assay,
        "' has no data layer; normalize it explicitly before plotting.",
        call. = FALSE
      )
    }
    features <- unique(features)
    missing_features <- setdiff(features, rownames(plot_object[[feature_assay]]))
    if (length(missing_features)) {
      stop("Feature(s) absent from assay '", feature_assay, "': ", paste(missing_features, collapse = ", "), call. = FALSE)
    }
    SeuratObject::DefaultAssay(plot_object) <- feature_assay
    plot <- Seurat::SpatialFeaturePlot(
      object = plot_object,
      features = features,
      images = contract$image,
      crop = crop,
      combine = TRUE,
      pt.size.factor = pt_size_factor,
      alpha = c(spot_alpha, spot_alpha),
      image.alpha = image_alpha,
      image.scale = image_scale
    )
  }

  if (!inherits(plot, c("gg", "ggplot", "patchwork"))) {
    stop("Seurat returned an unsupported plot object.", call. = FALSE)
  }
  plot
}

compose_shared_legend <- function(plots, ncol = NULL, position = "right") {
  if (!requireNamespace("patchwork", quietly = TRUE)) stop("Package 'patchwork' is required.")
  if (!is.list(plots) || !length(plots) || !all(vapply(plots, inherits, logical(1), what = "ggplot"))) stop("plots must be a non-empty list of ggplot objects.")
  patchwork::wrap_plots(plots, ncol = ncol, guides = "collect") & ggplot2::theme(legend.position = position)
}

# Generalized from the local plotting library. No file I/O or data mutation.
plot_umap_groups <- function(data, x = "umap_1", y = "umap_2", group = "cluster",
                             palette = NULL, point_size = 0.6, alpha = 0.75,
                             label_groups = FALSE, coordinate_padding = 0.16) {
  if (!requireNamespace("ggplot2", quietly = TRUE)) stop("Package 'ggplot2' is required.")
  needed <- c(x, y, group)
  if (!is.data.frame(data) || !all(needed %in% names(data))) {
    stop("data must be a data.frame containing: ", paste(needed, collapse = ", "))
  }
  if (!is.numeric(data[[x]]) || !is.numeric(data[[y]])) stop("x and y must be numeric.")
  if (length(coordinate_padding) != 1 || !is.finite(coordinate_padding) || coordinate_padding < 0) stop("coordinate_padding must be a non-negative number.")
  p <- ggplot2::ggplot(data, ggplot2::aes(x = .data[[x]], y = .data[[y]], colour = .data[[group]])) +
    ggplot2::geom_point(size = point_size, alpha = alpha, stroke = 0) +
    ggplot2::coord_equal() +
    ggplot2::scale_x_continuous(expand = ggplot2::expansion(mult = coordinate_padding)) +
    ggplot2::scale_y_continuous(expand = ggplot2::expansion(mult = coordinate_padding)) +
    ggplot2::labs(x = x, y = y, colour = group) +
    ggplot2::theme_classic(base_size = 11)
  if (!is.null(palette)) p <- p + ggplot2::scale_colour_manual(values = palette)
  if (isTRUE(label_groups)) {
    centres <- stats::aggregate(data[c(x, y)], list(group = data[[group]]), stats::median)
    p <- p + ggplot2::geom_text(
      data = centres,
      ggplot2::aes(x = .data[[x]], y = .data[[y]], label = .data[["group"]]),
      inherit.aes = FALSE, fontface = "bold", check_overlap = TRUE
    )
  }
  p
}
